"""
Christ Layer — 1 Chronicles chapters 19–22
Run: python3 scripts/zc-christ-1chronicles-19-22.py

Ch19: Ammonite war, rejected ambassador, Joab's speech.
Ch20: Rabbah captured, Philistine giants defeated.
Ch21: Satan's census, plague, the threshing floor of Ornan — the site of atonement.
Ch22: Threshing floor declared temple site; David's preparations; charge to Solomon.
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

CHRON1_CHRIST_19_22 = {
  "19": {
    "1": "<p>After the death of Nahash king of the Ammonites, David sends emissaries to comfort his son Hanun — an act of covenant kindness (<em>ḥesed</em>). The initiative of covenantal outreach that is misread and rejected prefigures the pattern of God&rsquo;s reconciling overtures throughout redemptive history: the prophets sent to Israel who were rejected (Luke 11:49-51), Christ himself as the supreme ambassador of divine <em>ḥesed</em> (John 1:11; 2 Cor 5:20) — &ldquo;He came to his own, and his own people did not receive him.&rdquo;</p>",
    "2": "<p>David says, &ldquo;I will deal loyally with Hanun the son of Nahash, for his father dealt loyally with me.&rdquo; The logic of covenant reciprocity — receiving kindness and returning it — is the logic of the kingdom of God. Jesus teaches his disciples to love as they have been loved (John 13:34; 15:12), to forgive as they have been forgiven (Matt 6:12; Eph 4:32). David&rsquo;s <em>ḥesed</em> toward Hanun models the grace-based ethic that flows from experienced covenant love.</p>",
    "3": "<p>Hanun&rsquo;s advisors interpret David&rsquo;s emissaries as spies — attributing malicious intent to a gesture of covenant kindness. The pattern of suspicion rejecting grace recurs throughout Scripture: the Pharisees interpreting Jesus&rsquo; healings as demonic (Matt 12:24), the world hating the disciples because it hated Christ first (John 15:18). The rejection of David&rsquo;s ambassadors becomes the occasion for war — as the rejection of Christ becomes the occasion for judgment (John 12:48).</p>",
    "4": "<p>Hanun shaved the emissaries&rsquo; beards and cut off their garments at the hips — a deliberate public humiliation designed to shame men whose identity was partially expressed in their beard and garment. The humiliation of YHWH&rsquo;s ambassadors is treated as an act of war. Jesus warns his disciples that as ambassadors of the kingdom they will face rejection and humiliation: &ldquo;A servant is not greater than his master. If they persecuted me, they will also persecute you&rdquo; (John 15:20). The rejected ambassador participates in Christ&rsquo;s own rejection.</p>",
    "5": "<p>David tells the humiliated men to wait at Jericho until their beards have grown — an act of compassion that treats their shame as temporary. The place of waiting — Jericho, the first city conquered in the land — is charged with symbolism: the city of victory becomes the place of patient restoration. Jesus&rsquo; instruction that his disciples wait in Jerusalem for the Spirit (Acts 1:4-5) follows the same pattern: before they can be sent as effective ambassadors, they must receive the power that transforms their shame into boldness (Acts 2:14-36).</p>",
    "6": "<p>The Ammonites, knowing they had made themselves odious to David, hired 32,000 chariots and horsemen from Aram. The escalation from an insult to a full military alliance against David recapitulates the pattern of the powers opposing YHWH&rsquo;s anointed: Ps 2:1-3 describes the nations conspiring against YHWH and his anointed, setting the typological template that the book of Acts reads as fulfilled in the conspiracy against Jesus (Acts 4:25-27). The coalition against David is a type of the coalition against Christ.</p>",
    "7": "<p>The combined Ammonite-Aramean force assembles against Israel — a coalition of nations aligned against YHWH&rsquo;s king. The constellation of kingdoms opposing the anointed David mirrors the eschatological battle imagery of Revelation: the kings of the earth gathered against the Lamb (Rev 19:19). But as David&rsquo;s coalition was defeated, Christ&rsquo;s final enemies are defeated not by military force but by the word of his mouth (Rev 19:15, 21).</p>",
    "8": "<p>Joab surveys the field and sees that the battle is arrayed against him both before and behind — enemies on two fronts. He divides his forces, taking the choice troops himself and entrusting the rest to his brother Abishai. The military wisdom of strategic deployment mirrors the divine wisdom in confronting evil: Christ sent his disciples two by two (Mark 6:7), and the church dispersed at persecution ended up spreading the gospel everywhere (Acts 8:4). What appears to be encirclement becomes the occasion for advance in multiple directions.</p>",
    "9": "<p>The Ammonites take up their position at the city gate while the kings who came stood apart in the open country. The Ammonite defense of the gate — the threshold of their city — is ironic in light of 1 Chronicles&rsquo; gatekeeper theology: human gatekeepers defending exclusion will fail, while the divine gatekeeper (Christ as the door, John 10:7-9) exercises inclusive authority, welcoming all who come through him.</p>",
    "10": "<p>Joab sees that the battle front is set against him both before and behind, so he chooses from all the choice men of Israel and deploys them against the Syrians. The strategic response to encirclement — choosing the best and directing them at the strongest threat — prefigures Christ&rsquo;s selection of disciples for his mission: he chose twelve (Mark 3:13-14), then seventy-two (Luke 10:1), and deployed them against the strongholds of spiritual darkness.</p>",
    "11": "<p>The rest of the people Joab puts in the hand of Abishai his brother — a division of leadership for maximum coverage. The parallel command structure of Joab and Abishai mirrors the apostolic partnership model of the NT: Paul and Barnabas, Paul and Silas, Peter and John — pairs of leaders advancing the kingdom on coordinated fronts (Acts 13:2; 15:22; Gal 2:9). The kingdom of God advances through partnership, not solo heroics.</p>",
    "12": "<p>&ldquo;If the Syrians are too strong for me, then you shall help me, but if the Ammonites are too strong for you, then I will help you.&rdquo; Mutual reinforcement within the body — the arm that cannot say to the foot &ldquo;I have no need of you&rdquo; (1 Cor 12:21). The church advances as a mutually supporting body, each member ready to reinforce those under pressure. This is the warfare logic of the spiritual community: &ldquo;if one member suffers, all suffer together&rdquo; (1 Cor 12:26).</p>",
    "13": "<p>&ldquo;Be strong, and let us act courageously for our people and for the cities of our God, and may the LORD do what seems good to him.&rdquo; Joab&rsquo;s battle-speech is the OT template for the NT call to spiritual courage: Paul echoes it almost verbatim — &ldquo;Be watchful, stand firm in the faith, act like men, be strong&rdquo; (1 Cor 16:13). Both speeches ground courage not in human confidence but in divine sovereignty: &ldquo;may the LORD do what seems good to him&rdquo; is the theology of Gethsemane — &ldquo;not my will, but yours be done&rdquo; (Luke 22:42).</p>",
    "14": "<p>Joab and the people with him draw near before the Syrians for battle, and the Syrians flee. The advance of God&rsquo;s people in faith causes the enemy to flee — the spiritual logic of James 4:7: &ldquo;Resist the devil, and he will flee from you.&rdquo; The Syrians&rsquo; flight models the retreat of spiritual adversaries before the advance of the people of God who move in obedience to the one who has disarmed the rulers and authorities (Col 2:15).</p>",
    "15": "<p>When the Ammonites see that the Syrians had fled, they also flee before Joab&rsquo;s brother Abishai. The cascading rout — when one part of the enemy coalition flees, the rest follows — is the spiritual pattern of Revelation: when the dragon is cast down, his servants lose their footing (Rev 12:9-12). Christ&rsquo;s defeat of Satan at the cross set in motion the cascading defeat of every spiritual power allied with him.</p>",
    "16": "<p>The Syrians, humiliated, send for more Syrians from beyond the Euphrates — a second coalition assembles under Shophach the commander of Hadadezer. The escalating opposition to David mirrors the intensifying opposition to Christ&rsquo;s kingdom in Rev 12–13 and 19: each military defeat produces a larger coalition, until the final confrontation at the great day. God permits the escalation because the final victory will be all the more complete.</p>",
    "17": "<p>David gathers all Israel and crosses the Jordan to meet the massed Syrian forces. The crossing of the Jordan — the covenant boundary of the land — with all Israel united against a common enemy has Exodus resonance: as Israel crossed the Jordan under Joshua to possess the land, David crosses it to defend and expand it. Christ&rsquo;s &ldquo;crossing&rdquo; — his baptism in the Jordan (Matt 3:13-17), his entry into enemy territory — is the definitive campaign to reclaim the whole earth for the Father.</p>",
    "18": "<p>David kills 7,000 charioteers and 40,000 foot soldiers of the Syrians; also Shophach the commander is killed. The numbers are stylized but the principle is clear: David&rsquo;s victory over the assembled coalition is overwhelming and total. As Christ&rsquo;s victory at the cross was total — &ldquo;It is finished&rdquo; (John 19:30) — the military vocabulary of David&rsquo;s campaigns provides the typological language for Paul&rsquo;s declaration: &ldquo;He disarmed the rulers and authorities and put them to open shame, triumphing over them in him&rdquo; (Col 2:15).</p>",
    "19": "<p>The servants of Hadadezer, seeing themselves defeated by Israel, make peace with David and become his servants — &ldquo;nor were the Syrians willing to save the Ammonites anymore.&rdquo; The formerly hostile nations become subjects of the Davidic kingdom — the typological template for the eschatological submission of the nations to Christ: &ldquo;the kingdom of the world has become the kingdom of our Lord and of his Christ, and he shall reign forever and ever&rdquo; (Rev 11:15; Ps 2:8; Phil 2:10-11). The defeated become the servant-subjects of the victorious King.</p>"
  },
  "20": {
    "1": "<p>In the spring — when kings go out to war — Joab leads Israel to ravage the Ammonites while David remains in Jerusalem. The Chronicler condenses the entire Bathsheba episode (2 Sam 11–12) into a narrative gap. By omitting David&rsquo;s gravest sin, the Chronicler presents the idealized David as a type of the coming king — not denying historical reality but focusing his lens on the Davidic covenant. Christ fulfills what David&rsquo;s type only pointed toward: a king without moral failure, the only one whose perfect reign can serve as the eternal temple of God&rsquo;s presence among his people.</p>",
    "2": "<p>David takes the crown of Milcom (the Ammonite god) from his head — its gold and precious stones placed on David&rsquo;s own head. The transfer of a defeated god&rsquo;s crown to the victorious king is a theological statement: YHWH&rsquo;s anointed king is greater than the false gods of the nations. Revelation depicts Christ as the one bearing &ldquo;many crowns&rdquo; (Rev 19:12) — the accumulated glory of all defeated false claimants to sovereignty transferred to the one true King. Every crown the nations offered their idols belongs by right to Christ.</p>",
    "3": "<p>David assigns the Ammonite population to work with saws, iron picks, and axes — forced labor in the service of the Davidic kingdom. The subjugation of the defeated is the ancient vocabulary for the subjugation of all creation to the dominion of the image-bearer (Gen 1:28; Ps 8:6). Paul reads this Adamic dominion as fulfilled in Christ: &ldquo;God has put all things in subjection under his feet&rdquo; (1 Cor 15:27; Eph 1:22; Heb 2:8) — including the &ldquo;last enemy,&rdquo; death itself.</p>",
    "4": "<p>Sibbecai the Hushathite strikes down Sippai, a descendant of the Rephaim — the race of giants. The campaign against the giants of Gath (vv4-8) itemizes the systematic elimination of every remaining giant the Philistines could field. In Israelite tradition the Rephaim/Nephilim represent the primordial threat to God&rsquo;s human image-bearers — the &ldquo;mighty men who were of old, the men of renown&rdquo; (Gen 6:4). The Davidic warriors who eliminate them one by one are types of Christ&rsquo;s definitive defeat of &ldquo;the one who has the power of death, that is, the devil&rdquo; (Heb 2:14).</p>",
    "5": "<p>Elhanan son of Jair strikes down Lahmi the brother of Goliath the Gittite — harmonizing the apparent contradiction with 2 Sam 21:19 where Elhanan kills Goliath himself (the Chronicler adds &ldquo;the brother of&rdquo;). The Davidic warriors continue the work David began at the Valley of Elah: the giant Goliath who dominated and paralyzed all Israel is overcome — and now his family line is systematically defeated. As Christ defeated the accuser at the cross and now his people continue to overcome him &ldquo;by the blood of the Lamb and by the word of their testimony&rdquo; (Rev 12:11), the Davidic warriors&rsquo; campaign extends their king&rsquo;s initial victory.</p>",
    "6": "<p>A man of great stature — six fingers on each hand and six toes on each foot: twenty-four digits — defies Israel. The giant&rsquo;s physical abnormality marks him as belonging to a different order of humanity, the corrupted line that must be eliminated for the image of God to be restored. The number 24 is associated in Revelation with the 24 elders around the throne (Rev 4:4) — the perfected community of God&rsquo;s redeemed. The abnormal 24 of the giant&rsquo;s digits is a dark mirror of the redeemed 24; Christ&rsquo;s victory over the corrupted order makes way for the restored order of the new creation.</p>",
    "7": "<p>Jonathan son of Shimea, David&rsquo;s brother, strikes him down. The elimination of the last giant — by a member of David&rsquo;s own family — signals the completion of David&rsquo;s conquest program. The final enemy overcome by a member of the king&rsquo;s household mirrors the eschatological defeat of death: &ldquo;the last enemy to be destroyed is death&rdquo; (1 Cor 15:26), and it is destroyed not by a human warrior but by the Son of Man who entered death and emerged victorious (Rev 1:18: &ldquo;I died, and behold I am alive forevermore, and I have the keys of Death and Hades&rdquo;).</p>",
    "8": "<p>&ldquo;These were descended from the giants in Gath, and they fell by the hand of David and by the hand of his servants.&rdquo; The summary verdict — the entire giant opposition eliminated &ldquo;by the hand of David and his servants&rdquo; — is the OT template for 1 Cor 15:57: &ldquo;Thanks be to God, who gives us the victory through our Lord Jesus Christ.&rdquo; The victory belongs to the king; his servants participate in it. The church does not achieve victory independently but shares in the victory Christ has won — &ldquo;more than conquerors through him who loved us&rdquo; (Rom 8:37).</p>"
  },
  "21": {
    "1": "<p>Satan (<em>śāṭān</em>) stands against Israel and incites David to number Israel — replacing the ambiguous &ldquo;YHWH incited David&rdquo; of 2 Sam 24:1 with the explicit adversary. The Chronicler&rsquo;s editorial decision names the behind-the-scenes instigator: Satan, operating within divine permission, exploits David&rsquo;s pride to commit a sin that costs Israel dearly. This is the OT&rsquo;s clearest presentation of Satanic temptation in the royal narrative, pointing forward to Satan&rsquo;s temptation of Jesus (Matt 4:1-11; Luke 22:31-32) and Peter&rsquo;s naming of the adversary as a prowling lion (1 Pet 5:8). Christ faced and defeated the same adversary David fell before.</p>",
    "2": "<p>David orders Joab and the military commanders to number Israel from Beersheba to Dan. The census is a military audit — counting swords rather than trusting YHWH of hosts. The pride of counting one&rsquo;s military resources rather than relying on YHWH is the sin of the king who trusts in horses and chariots rather than in the name of YHWH (Ps 20:7; Prov 21:31). Jesus refuses every temptation to leverage power for self-preservation (Matt 4:3-10) — the perfect antithesis of David&rsquo;s census-pride.</p>",
    "3": "<p>Joab objects: &ldquo;May the LORD add to his people a hundred times as many as they are! Are they not, my lord the king, all of them my lord&rsquo;s servants?&rdquo; The military commander shows more theological wisdom than the king — recognizing that numbering Israel treats God&rsquo;s people as a human military asset rather than as YHWH&rsquo;s own possession. The irony is profound: the servant reproves the king on spiritual grounds. In the kingdom of Christ, the first are last and servants are honored above those who seek positions of power (Matt 20:26-27).</p>",
    "4": "<p>The king&rsquo;s word prevails against Joab. David&rsquo;s royal authority overrides Joab&rsquo;s theological wisdom — the pride that makes a man unteachable is the sin beneath the sin. The Chronicler presents the census not merely as administrative error but as the symptom of a heart that has elevated its own judgment above divine wisdom. This is the same pride that afflicts every human leader who confuses authority over God&rsquo;s people with ownership of God&rsquo;s people — a confusion Christ definitively corrects: &ldquo;You are not your own; you were bought with a price&rdquo; (1 Cor 6:19-20).</p>",
    "5": "<p>The census count — 1,100,000 men in Israel and 470,000 in Judah. The Chronicler&rsquo;s numbers differ from Samuel&rsquo;s (2 Sam 24:9) in ways that suggest different counting methods rather than contradiction. But the theological point transcends arithmetic: a numbered army that trusts in its own size is, by that trust, weakened. Gideon&rsquo;s 300 are worth more than Midian&rsquo;s 135,000 (Judg 7). The kingdom of God advances not through superior numbers but through the power of the one who multiplied five loaves to feed five thousand (Matt 14:17-21) — the Lord of armies who needs no census.</p>",
    "6": "<p>Levi and Benjamin Joab does not number — his resistance to the census preserves these two central tribes from the forthcoming judgment. Benjamin will be the tribe of Paul; Levi will provide the temple priests. Their exemption from the census-sin may be coincidental in the narrative, but typologically they represent those who are not counted among those who trust in military might: the servant-tribe (Levi) and the remnant tribe (Benjamin) are preserved apart from the king&rsquo;s proud audit.</p>",
    "7": "<p>&ldquo;But God was displeased with this thing, and he struck Israel.&rdquo; Divine displeasure at the census leads immediately to judgment — the pattern of covenant consequence. The speed of judgment suggests that this sin struck at something fundamental: the identity of Israel as a people who depend on YHWH alone. The plague that follows (vv14-15) functions as a dramatic sign of what happens when God&rsquo;s people trust in their own strength: the very thing they counted — their military population — is reduced. Christ&rsquo;s way is the inverse: strength made perfect in weakness (2 Cor 12:9).</p>",
    "8": "<p>David acknowledges: &ldquo;I have sinned greatly in that I have done this thing. But now, please take away the iniquity of your servant, for I have acted very foolishly.&rdquo; The immediacy of David&rsquo;s confession — no rationalization, no deflection — is the hallmark of his character that distinguishes him from Saul. As Jesus taught, the one who acknowledges sin receives mercy (Luke 18:13-14; 1 John 1:9). David&rsquo;s penitential response to Nathan&rsquo;s rebuke (2 Sam 12:13; Ps 51) and to Gad&rsquo;s oracle here models the contrite heart that Christ promises will not be despised (Ps 51:17).</p>",
    "9": "<p>YHWH speaks to Gad, David&rsquo;s seer — the prophetic word mediating divine judgment and mercy. The triad of prophetic figures (Samuel, Nathan, Gad) who speak to David corresponds to the prophetic office fulfilled in Christ, who is &ldquo;the prophet&rdquo; (Deut 18:15; John 6:14; Acts 3:22) — the one through whom the definitive divine word comes. Every prophetic word from Gad and Nathan is a partial delivery of the word that becomes flesh in Christ.</p>",
    "10": "<p>YHWH offers David a choice of three judgments: three years of famine, three months of defeat by enemies, or three days of plague. The structure of three options with the plague as the quickest but most severe echoes the principle that judgment is better to receive from YHWH than from human enemies (v13). David&rsquo;s response — &ldquo;Let me fall into the hand of the LORD, for his mercy is very great; but do not let me fall into the hand of man&rdquo; — is the theology of the cross: God&rsquo;s judgment received in faith is the path to mercy, while human judgment offers no mercy at all.</p>",
    "11": "<p>Gad comes to David and presents the three options. The prophetic figure who comes to the king with a word of judgment-and-choice is the OT type of the Spirit who &ldquo;convicts the world concerning sin and righteousness and judgment&rdquo; (John 16:8). The moment of prophetic confrontation is the moment of decision: every person stands before the same choice David faced — to receive YHWH&rsquo;s discipline in humility, or to resist it in pride.</p>",
    "12": "<p>Three years of famine, three months of sword, or three days of plague — the triad of covenant judgments drawn from the curse-list of Deut 28 and Lev 26. The covenant framework of blessing and cursing established at Sinai is the background against which David&rsquo;s sin is evaluated. Christ has redeemed believers from the curse of the law by becoming a curse for them (Gal 3:13) — absorbing the covenant penalties that David&rsquo;s people faced here, so that judgment falls on the one and not the many.</p>",
    "13": "<p>&ldquo;I am in great distress. Let me fall into the hand of the LORD, for his mercies are very great; but do not let me fall into human hands.&rdquo; David&rsquo;s choice is theological: YHWH&rsquo;s judgment, however severe, is bounded by <em>raḥămîm</em> (compassion/mercies) — the same word root as <em>reḥem</em> (womb), connoting the deep maternal love of YHWH for Israel (Isa 49:15; 63:15). Human enemies show no such restraint. The theology of divine judgment as ultimately merciful is crystallized in the cross: the worst judgment falls on the Son so that mercy might flow to the many.</p>",
    "14": "<p>YHWH sends a pestilence on Israel — 70,000 men fall. The number 70 is the number of the nations (Gen 10) and of Israel&rsquo;s elders (Num 11:16-25) — the round number of complete representative loss. The plague that kills 70,000 men stops when the angel reaches Jerusalem. As the death angel passed over the houses with blood on the doorposts at Passover (Exod 12:23), the plague is arrested here by an act of atonement — the logic of sacrifice substituted for the people&rsquo;s sin.</p>",
    "15": "<p>God sends the angel to destroy Jerusalem, but as the angel stretches out his hand over Jerusalem, YHWH relents of the disaster and says to the destroying angel, &ldquo;It is enough; now stay your hand.&rdquo; The scene — the divine warrior staying the destroying angel at the threshing floor — is the OT&rsquo;s most dramatic picture of divine relenting (<em>niḥam</em>). The author of Hebrews reads Christ&rsquo;s sacrifice as the definitive <em>niḥam</em>: &ldquo;he appeared once for all at the end of the ages to put away sin by the sacrifice of himself&rdquo; (Heb 9:26). The angel was stayed at Ornan&rsquo;s threshing floor; judgment was stayed at Golgotha.</p>",
    "16": "<p>David lifts his eyes and sees the angel of YHWH standing between earth and heaven, with a drawn sword stretched out over Jerusalem — and he and the elders fall on their faces, clothed in sackcloth. The vision of the angelic warrior suspended between heaven and earth, sword drawn, is the theophany that drives David to penitential prostration. The drawn sword that threatened Israel finds its resolution in the sword that struck the Shepherd (Zech 13:7; Matt 26:31) — as if the angel&rsquo;s blade was finally sheathed into the body of Christ, exhausting its judgment there.</p>",
    "17": "<p>&ldquo;Was it not I who gave the command to number the people? It is I who have sinned and done great evil. But these sheep, what have they done? Please let your hand, O LORD my God, be against me and against my father&rsquo;s house. But do not let the plague be on your people.&rdquo; David&rsquo;s intercession — taking the guilt upon himself to spare the people — is the clearest typological anticipation of substitutionary atonement in the David narrative: the king who stands between the angel and the people, offering himself. Christ the king of David&rsquo;s line fulfills what David could only type: &ldquo;the good shepherd lays down his life for the sheep&rdquo; (John 10:11; Isa 53:4-6).</p>",
    "18": "<p>The angel of YHWH commands Gad to tell David to go and set up an altar to YHWH on the threshing floor of Ornan the Jebusite. The divine command to build an altar at a specific site — the Jebusite threshing floor — is an act of divine designation: YHWH himself is choosing the place where sacrifice and atonement will permanently occur. The site that began as a plague-stopping emergency altar becomes the permanent foundation of the Temple — as the cross that was the &ldquo;emergency&rdquo; of divine love becomes the permanent foundation of the new covenant community.</p>",
    "19": "<p>David went up at the word of Gad, which he spoke in the name of YHWH. The obedience of prophetic word is the mechanism of salvation in 1 Chronicles: the king who had disobeyed now obeys immediately. The contrast with Saul — who disobeyed the prophetic word and died — is exact. Christ&rsquo;s obedience to the Father&rsquo;s will (&ldquo;not my will but yours be done,&rdquo; Luke 22:42) is the perfect fulfillment of the king who hears and obeys the prophetic word, even when the word leads to the place of sacrifice.</p>",
    "20": "<p>Ornan was threshing wheat, turned and saw the angel — and his four sons hid themselves. Ornan, a Jebusite (the pre-Israelite inhabitants of Jerusalem), is on the site when the divine mandate comes. That a Jebusite owns the land of the future temple grounds is theologically significant: YHWH is purchasing the temple site from a Gentile, integrating non-Israelite history into the story of Israel&rsquo;s worship. The Gentile at the center of the atonement-site foreshadows the Gentiles&rsquo; inclusion in the new covenant temple (Eph 2:19-22).</p>",
    "21": "<p>As David approaches, Ornan looks up and sees David, and goes out from the threshing floor and bows to David with his face to the ground. The Jebusite&rsquo;s act of submission to the Davidic king at the place that will become the temple mirrors the eschatological vision of all nations bowing before the greater Son of David (Phil 2:9-11; Ps 22:27). Every knee will bow at the place where atonement was made — the threshing floor of judgment becomes the altar of mercy.</p>",
    "22": "<p>David asks Ornan to sell him the threshing floor site so he can build an altar — &ldquo;that the plague may be averted from the people.&rdquo; The purpose of the purchase is explicit: atoning sacrifice requires a designated, legitimately acquired site. God does not commandeer what does not belong to his people; he purchases it. The legitimate purchase of the atonement site parallels the garden tomb, purchased and provided for Jesus&rsquo; burial (Matt 27:59-60; John 19:41) — the places of death and resurrection properly secured, not seized.</p>",
    "23": "<p>Ornan offers everything freely — the threshing floor, the oxen for the burnt offering, the threshing sledges for wood, and the wheat for the grain offering. The Jebusite&rsquo;s generosity in providing the full sacrifice at no cost is a remarkable act of grace — the outsider supplying what is needed for Israel&rsquo;s atonement. Yet David insists on paying full price: &ldquo;I will not take for the LORD what is yours, nor offer burnt offerings that cost me nothing.&rdquo; The sacrifice must cost the offerer something. The cross cost the Son everything — &ldquo;he who did not spare his own Son but gave him up for us all&rdquo; (Rom 8:32).</p>",
    "24": "<p>&ldquo;No, but I will buy it for the full price. I will not take for the LORD what is yours, nor offer burnt offerings that cost me nothing.&rdquo; David&rsquo;s insistence on paying full price is the principle of costly worship: as Mary&rsquo;s &ldquo;waste&rdquo; of expensive perfume (Mark 14:3-9) and the widow&rsquo;s two mites (Luke 21:1-4) demonstrate, God values the sacrifice that costs the worshiper dearly over the donation that costs nothing. David&rsquo;s logic is the logic of the cross: the offering that saves must be costly enough to be real.</p>",
    "25": "<p>David pays 600 gold shekels for the site. The full price — generous beyond necessity — underlines the theological significance of legitimate acquisition. The place of atonement is properly owned by God&rsquo;s people before sacrifice can be offered there. Christ is described as having &ldquo;purchased&rdquo; the church with his own blood (Acts 20:28; 1 Cor 6:20; Rev 5:9) — the ultimate full-price transaction that establishes the legitimate ownership of the people who now form the living temple (1 Cor 3:16).</p>",
    "26": "<p>David builds an altar to YHWH there and offers burnt offerings and peace offerings, and calls on YHWH — and YHWH answers him with fire from heaven upon the altar of burnt offering. Fire from heaven is the consistent OT sign of divine acceptance of sacrifice: Sinai (Lev 9:24), Elijah on Carmel (1 Kgs 18:38), Solomon&rsquo;s temple dedication (2 Chr 7:1). The fire that falls on David&rsquo;s emergency altar designates Ornan&rsquo;s threshing floor as the divinely accepted place of sacrifice. The Pentecostal fire (Acts 2:3) falls on the church as the new temple — the Father&rsquo;s acceptance of the Son&rsquo;s sacrifice now signified in the gift of the Spirit.</p>",
    "27": "<p>YHWH commanded the angel, and he put his sword back into its sheath. The drawn sword sheathed — the judgment stayed — is the Chronicler&rsquo;s image of atonement accomplished. When sacrifice is offered and accepted, the sword of divine justice returns to its scabbard. The same image appears at the cross in its negative form: Jesus does not call twelve legions of angels (Matt 26:53) — he lets the sword fall on himself so it can be sheathed. &ldquo;He who knew no sin became sin for us, so that in him we might become the righteousness of God&rdquo; (2 Cor 5:21).</p>",
    "28": "<p>At that time, when David sees that YHWH has answered him at the threshing floor of Ornan the Jebusite, he sacrifices there. The response to divine acceptance is continued worship — the logic of gratitude generating ongoing sacrifice. The church&rsquo;s eucharistic worship is precisely this: response to the fire-from-heaven acceptance of Christ&rsquo;s sacrifice, the ongoing &ldquo;sacrifice of praise&rdquo; (Heb 13:15) that the community offers at the place where atonement has been made.</p>",
    "29": "<p>The tabernacle of YHWH made in the wilderness, and the altar of burnt offering, are at that time in the high place at Gibeon. Two legitimate altars exist simultaneously — the Mosaic one at Gibeon and the new one at Ornan&rsquo;s threshing floor. The duplication signals a transition: the Mosaic worship structure is about to be superseded by the Davidic-Solomonic temple. As the tabernacle gave way to the temple, the temple gave way to the one whose body is the true temple (John 2:21; Col 2:17): in Christ, both Mosaic and Davidic worship find their fulfillment and their end.</p>",
    "30": "<p>David cannot go before the tabernacle at Gibeon to inquire of God, because he is afraid of the sword of the angel of YHWH. The fear that keeps David at the new altar rather than the old one is itself a divine redirection: the old worship site at Gibeon is being superseded by the new one at Ornan&rsquo;s threshing floor. God uses David&rsquo;s fear to accomplish his purposes — the new worship center is being established precisely where atonement has just been made. Providence works through human limitations to direct history toward its appointed ends.</p>"
  },
  "22": {
    "1": "<p>&ldquo;Then David said, &lsquo;This is the house of the LORD God, and this is the altar of burnt offering for Israel.&rsquo;&rdquo; David&rsquo;s declaration transforms the threshing floor into sacred space — the place where judgment was stayed, sacrifice was offered, and fire fell from heaven is designated the permanent dwelling of God. Jesus makes the same move about his body: &ldquo;Destroy this temple, and in three days I will raise it up&rdquo; (John 2:19-21). As the threshing floor became the temple, the resurrection body of Christ is the true and final temple — and his body, the church, is now the &ldquo;holy temple in the Lord&rdquo; (Eph 2:21).</p>",
    "2": "<p>David commands the resident aliens (<em>gēr</em>) in Israel to be gathered — stonecutters to prepare building materials. The employment of non-Israelite workers in temple preparation echoes the Solomonic corvée (1 Kgs 5:13-18) and foreshadows the nations&rsquo; contribution to the eschatological temple: &ldquo;the wealth of the nations shall come to you&rdquo; (Isa 60:5); &ldquo;the kings of the earth will bring their glory into it&rdquo; (Rev 21:24). The Gentiles who contribute their skills to God&rsquo;s house are a type of the nations streaming to Zion.</p>",
    "3": "<p>David prepares iron in abundance for the nails for the doors of the gates and for clamps, and bronze in quantities beyond weighing. The vast material preparation for a building David will never complete is itself a theological act: David pours himself into a project whose completion he will not see, trusting that God will bring it to fulfillment through his son. The disciples of Jesus are called to the same posture — working for a kingdom whose fullness they will not see in their lifetimes (Heb 11:13-16: they &ldquo;died in faith, not having received the things promised&rdquo;).</p>",
    "4": "<p>Cedar timber beyond counting, for Sidon and Tyre bring cedar logs without limit to David. The commerce of Phoenicia serving the temple of YHWH anticipates Isaiah&rsquo;s vision of the nations bringing their wealth to the glory of Jerusalem (Isa 60:1-14) and Revelation&rsquo;s vision of the nations&rsquo; kings bringing their glory into the New Jerusalem (Rev 21:24-26). The universal provision of temple materials from all directions is a sign of the cosmic scope of God&rsquo;s house.</p>",
    "5": "<p>&ldquo;Solomon my son is young and inexperienced, and the house that is to be built for the LORD must be exceedingly magnificent.&rdquo; David prepares abundantly precisely because the builder is young and the task exceeds human capacity. The Father&rsquo;s provision of resources for his Son&rsquo;s mission mirrors this: Jesus was sent into the world with the full provision of the Spirit (John 3:34: &ldquo;he gives the Spirit without measure&rdquo;) to accomplish the task that no mere man could complete. David&rsquo;s vast preparation is the shadow of the Father&rsquo;s lavish provision for the Son.</p>",
    "6": "<p>David calls Solomon his son and charges him to build the house of YHWH the God of Israel. The father-to-son transmission of the divine commission is the model of apostolic sending: as the Father sent the Son, the Son sends the apostles (John 20:21), and the apostles send their successors (2 Tim 2:2). The Davidic transmission of the temple-building commission is the OT type of the Trinitarian sending that structures the entire mission of God.</p>",
    "7": "<p>&ldquo;My son, I had it in my heart to build a house to the name of YHWH my God. But the word of YHWH came to me, saying, &lsquo;You have shed much blood and have waged great wars. You shall not build a house to my name.&rsquo;&rdquo; David is a great king whose very greatness — the wars that secured the kingdom — disqualifies him from the work of peace. God does not reject David but redirects him: the warrior prepares; the man of peace builds. The Chronicler anticipates Paul&rsquo;s theology of grace: God works through human limitation, not despite it.</p>",
    "8": "<p>&ldquo;Behold, a son shall be born to you who shall be a man of rest. I will give him rest from all his surrounding enemies. For his name shall be Solomon, and I will give peace and quiet to Israel in his days.&rdquo; Solomon (<em>Šᵉlōmōh</em>) derives from <em>šālôm</em> (peace) — the man of rest and peace who builds what the warrior king could not. Jesus is explicitly identified as our peace: &ldquo;he himself is our peace, who has made us both one and has broken down in his flesh the dividing wall of hostility&rdquo; (Eph 2:14). Solomon&rsquo;s shalom-kingdom is the type; Christ&rsquo;s kingdom of peace is the antitype — established not by military victory but by the cross, the ultimate shedding of blood that paradoxically ends the need for blood-shedding.</p>",
    "9": "<p>Solomon will be a man of rest, and YHWH gives him rest from all his enemies — this is why his name is Solomon (<em>Šᵉlōmōh</em> = peace). The rest YHWH gives to Solomon from his enemies is the typological template for the rest Christ provides: &ldquo;Come to me, all who labor and are heavy laden, and I will give you rest&rdquo; (Matt 11:28); &ldquo;there remains a Sabbath rest for the people of God&rdquo; (Heb 4:9). The peace-rest of the Solomonic era is the shadow of the eternal rest that the Son of David offers to all who come to him.</p>",
    "10": "<p>&ldquo;He shall build a house for my name. He shall be my son, and I will be his father, and I will establish his royal throne in Israel forever.&rdquo; The father-son formula and the eternal throne promise crystallize the Davidic covenant of 2 Sam 7. The author of Hebrews quotes this verse (combining 2 Sam 7:14 and Ps 2:7) as fulfilled in Christ: &ldquo;To which of the angels did God ever say, &lsquo;You are my Son, today I have begotten you&rsquo;? Or again, &lsquo;I will be to him a father, and he shall be to me a son&rsquo;?&rdquo; (Heb 1:5). The son who builds the Father&rsquo;s house in 1 Chronicles 22 is the type whose ultimate fulfillment is the eternal Son who is himself the house of God (John 2:21; Eph 2:20-22).</p>",
    "11": "<p>&ldquo;Now, my son, the LORD be with you, so that you may succeed in building the house of YHWH your God, as he has spoken concerning you.&rdquo; The paternal blessing formula — YHWH be with you — is the identical formula with which the angel greets Mary (Luke 1:28) and which YHWH spoke to every figure at the threshold of a major commission (Josh 1:5; Judg 6:12; 2 Chr 15:2). The divine presence-promise is the condition of all successful kingdom-building: &ldquo;Unless the LORD builds the house, those who build it labor in vain&rdquo; (Ps 127:1).</p>",
    "12": "<p>&ldquo;Only, may the LORD grant you discretion and understanding, that when he gives you charge over Israel you may keep the law of the LORD your God.&rdquo; Wisdom for obedience — <em>śēkel</em> and <em>bînāh</em> (prudence and understanding) — is what David asks for Solomon. The same request underlies the NT&rsquo;s theology of the Spirit as the Spirit of wisdom and revelation (Eph 1:17; Isa 11:2). Christ, in whom &ldquo;are hidden all the treasures of wisdom and knowledge&rdquo; (Col 2:3), is the source of the wisdom that makes obedience possible — the one in whom discretion and understanding find their perfect embodiment.</p>",
    "13": "<p>&ldquo;Then you will prosper if you are careful to observe the statutes and the rules that the LORD commanded Moses for Israel. Be strong and courageous. Fear not; do not be dismayed.&rdquo; The Deuteronomistic charge to Joshua (Josh 1:6-9) is here repeated to Solomon: covenant obedience is the condition of prosperity and courage. Christ fulfills this command from the inside out — not as external law but as the living Torah (John 1:14; 14:6), who embodies the statutes and rules in his own person and empowers his people to walk in them (Rom 8:4; 2 Cor 3:3).</p>",
    "14": "<p>David has prepared 100,000 talents of gold, 1,000,000 talents of silver, and bronze and iron beyond weighing — timber and stone besides. The numbers are theological rather than historical: they signal incomprehensible abundance, the lavishness of divine provision. As the Father has prepared every spiritual blessing for the Son&rsquo;s people in Christ (Eph 1:3) — riches that are &ldquo;unsearchable&rdquo; (Eph 3:8) — David&rsquo;s material preparation is a material type of the inexhaustible spiritual provision of the new covenant.</p>",
    "15": "<p>&ldquo;With you there are workmen in abundance: stonecutters, masons, carpenters, and all kinds of craftsmen without number, skilled in working gold, silver, bronze, and iron.&rdquo; The gifted builders for the temple are a type of the Spirit-gifted community that builds the living temple: &ldquo;to each is given the manifestation of the Spirit for the common good&rdquo; (1 Cor 12:7; Eph 4:11-12). The temple-builders of David&rsquo;s preparation represent every member of the body of Christ whose Spirit-given gifts contribute to the building up of the church.</p>",
    "16": "<p>&ldquo;Arise and be doing! The LORD be with you!&rdquo; David&rsquo;s charge to Solomon — <em>qûm wᵃʿăśēh</em> (arise and act/do) — is the language of commission: the same word (<em>qûm</em>) used when the Spirit stirs Samson (Judg 13:25), when Joshua is charged to rise and cross the Jordan (Josh 1:2), when the prophet is sent. Christ&rsquo;s commission to his disciples is in the same register: &ldquo;Go therefore and make disciples of all nations&rdquo; (Matt 28:19) — the imperative of mission entrusted to those whom the Lord equips.</p>",
    "17": "<p>David commands all the leaders of Israel to help Solomon his son, saying: YHWH your God is with you, and has given you rest on every side. The Davidic king enlists the entire leadership of Israel in the temple project — the community-wide mobilization of all resources for God&rsquo;s house. Paul&rsquo;s vision of the whole church building up the body of Christ (Eph 4:15-16; 1 Cor 3:9-15) echoes this total mobilization: no one is exempt from contributing to the building of the living temple.</p>",
    "18": "<p>&ldquo;Is not the LORD your God with you? And has he not given you rest on every side? For he has delivered the inhabitants of the land into my hand, and the land is subdued before the LORD and before his people.&rdquo; The rest from enemies is the condition for temple-building: the wars must end before the house of peace can be built. Christ&rsquo;s declaration — &ldquo;It is finished&rdquo; (John 19:30) — is the cosmic <em>shalom</em> that makes permanent temple-building possible: the warfare between God and humanity is over, the enemies are subdued, and the people can now build in peace.</p>",
    "19": "<p>&ldquo;Now set your mind and heart to seek the LORD your God. Arise and build the sanctuary of the LORD God, so that the ark of the covenant of the LORD and the holy vessels of God may be brought into a house built for the name of the LORD.&rdquo; The charge ends where Chronicles always returns: <em>dāraš YHWH</em> (seek the LORD) is the heart-disposition from which all true action flows. Christ is the ultimate Seeker-of-the-Father and the one who enables his people to seek: &ldquo;seek first the kingdom of God and his righteousness&rdquo; (Matt 6:33). The ark and the holy vessels that are to be housed — the presence of God dwelling among his people — find their final antitype in Christ, the one in whom &ldquo;all the fullness of God was pleased to dwell&rdquo; (Col 1:19; John 1:14).</p>"
  }
}

def main():
    existing = load_comm('mkt-christ', '1chronicles')
    merge_comm(existing, CHRON1_CHRIST_19_22)
    save_comm('mkt-christ', '1chronicles', existing)
    print('1 Chronicles 19-22 christ layer written.')

if __name__ == '__main__':
    main()
